(window["webpackJsonp"]=window["webpackJsonp"]||[]).push([["learn0"],{6626:function(n,e,o){"use strict";o.r(e);var r=function(){var n=this,e=n.$createElement,r=n._self._c||e;return r("markdown",{attrs:{source:o("bfac")}})},t=[],a=o("2877"),c={},s=Object(a["a"])(c,r,t,!1,null,null,null);s.options.__file="docker.vue";e["default"]=s.exports},bfac:function(n,e){n.exports="### Docker学习\nDocker安装地址(建议在虚拟机上安装)\n```\nhttps://docs.docker.com/\n```\n\n所以就先得安装一台虚拟机，推荐VirtualBox，安装地址是：\n```\nhttps://www.virtualbox.org/wiki/Downloads\n```\n有了虚拟机之后，就可以虚拟化一台Linux机器了。但是如果手动创建的话会比较繁琐，推荐vagrant工具来进行管理就比较方便，vagrant的安装地址是： \n```\nhttps://www.vagrantup.com\n```\n\n### Vagrant&VirtualBox for Mac\n通过vagrant创建一台虚拟机\n```s\n# 查看vagrant命令\nvagrant --help\n# 进入到/Users/zhangyu/xnj目录\ncd /Users/zhangyu/xnj\n# 创建一个centos7文件夹\nmkdir centos7\n# 进入到centos7下边\ncd centos7\n# 初始化一个centos7\nvagrant init centos/7\n# 查看vagrantfile文件\nmore vagrantfile\n# 创建启动虚拟机\nvagrant up\n# 进入到刚才创建的虚拟机\nvagrant ssh\n# 查看当前虚拟机的状态\nvagrant status\n# 停掉虚拟机\nvagrant halt\n# 删掉虚拟机\nvagrant destroy\n# 切换帐号 （root／vagrant，默认密码都是vagrant）\nsu\n```\nvagrantfile文件的配置说明，请参考下边网址：\n```\nhttps://app.vagrantup.com/boxes/search\n```\n\n### Vagrant&VirtualBox for Windows\n```\n与Mac类似\n```\n\n### CentOS上安装Docker\n\n卸载docker\n```\nsudo yum remove docker \\\n                  docker-client \\\n                  docker-client-latest \\\n                  docker-common \\\n                  docker-latest \\\n                  docker-latest-logrotate \\\n                  docker-logrotate \\\n                  docker-selinux \\\n                  docker-engine-selinux \\\n                  docker-engine\n```\n\n安装packages\n```\nsudo yum install -y yum-utils \\\n  device-mapper-persistent-data \\\n  lvm2\n```\n安装repo\n```\nsudo yum-config-manager \\\n    --add-repo \\\n    https://download.docker.com/linux/centos/docker-ce.repo\n```\n安装docker-ce\n```\nsudo yum install docker-ce\n```\n\n启动Docker\n```\nsudo systemctl start docker\n```\n打印Client和Server端的版本\n```\nsudo docker version\n```\n运行一个hello world\n```\nsudo docker run hello-world\n```"}}]);